code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [m, n] = input.split(' ').map(Number);
    console.log(Math.floor((m * n) / 2));
    rl.close();
});
